using UnityEngine;\nusing System;\n\n[System.Serializable]\npublic class PlayerProfile\n{\n    public string playerName = \"Player\";\n    public string countryCode = \"US\"; // ISO 3166-1 alpha-2\n    public string countryName = \"United States\";\n    public int totalScore = 0;\n    public int totalLevelsCompleted = 0;\n    public int currentLevel = 1;\n    public int totalEnemiesDefeated = 0;\n    public int totalPlayTime = 0; // in seconds\n    public DateTime lastPlayedDate;\n    public int consecutiveDaysPlayed = 0;\n    public int gamesPlayed = 0;\n    public float averageScorePerLevel = 0f;\n    public int rank = 0; // Leaderboard rank\n\n    public PlayerProfile()\n    {\n        lastPlayedDate = DateTime.Now;\n    }\n}\n\npublic class PlayerProfileManager : MonoBehaviour\n{\n    public static PlayerProfileManager Instance { get; private set; }\n\n    private PlayerProfile playerProfile;\n    private const string PROFILE_KEY = \"PlayerProfile\";\n    private const string COUNTRY_CODE_KEY = \"CountryCode\";\n    private const string PLAYER_NAME_KEY = \"PlayerName\";\n    private const string TOTAL_SCORE_KEY = \"TotalScore\";\n    private const string LEVELS_COMPLETED_KEY = \"LevelsCompleted\";\n    private const string ENEMIES_DEFEATED_KEY = \"EnemiesDefeated\";\n    private const string GAMES_PLAYED_KEY = \"GamesPlayed\";\n\n    private void Awake()\n    {\n        if (Instance != null && Instance != this)\n        {\n            Destroy(gameObject);\n            return;\n        }\n\n        Instance = this;\n        DontDestroyOnLoad(gameObject);\n        LoadPlayerProfile();\n    }\n\n    private void LoadPlayerProfile()\n    {\n        playerProfile = new PlayerProfile();\n\n        // Load from PlayerPrefs\n        playerProfile.playerName = PlayerPrefs.GetString(PLAYER_NAME_KEY, \"Player\");\n        playerProfile.countryCode = PlayerPrefs.GetString(COUNTRY_CODE_KEY, \"US\");\n        playerProfile.totalScore = PlayerPrefs.GetInt(TOTAL_SCORE_KEY, 0);\n        playerProfile.totalLevelsCompleted = PlayerPrefs.GetInt(LEVELS_COMPLETED_KEY, 0);\n        playerProfile.totalEnemiesDefeated = PlayerPrefs.GetInt(ENEMIES_DEFEATED_KEY, 0);\n        playerProfile.gamesPlayed = PlayerPrefs.GetInt(GAMES_PLAYED_KEY, 0);\n        playerProfile.countryName = GetCountryName(playerProfile.countryCode);\n\n        Debug.Log($\"Player Profile Loaded: {playerProfile.playerName} from {playerProfile.countryName}\");\n    }\n\n    public void SavePlayerProfile()\n    {\n        PlayerPrefs.SetString(PLAYER_NAME_KEY, playerProfile.playerName);\n        PlayerPrefs.SetString(COUNTRY_CODE_KEY, playerProfile.countryCode);\n        PlayerPrefs.SetInt(TOTAL_SCORE_KEY, playerProfile.totalScore);\n        PlayerPrefs.SetInt(LEVELS_COMPLETED_KEY, playerProfile.totalLevelsCompleted);\n        PlayerPrefs.SetInt(ENEMIES_DEFEATED_KEY, playerProfile.totalEnemiesDefeated);\n        PlayerPrefs.SetInt(GAMES_PLAYED_KEY, playerProfile.gamesPlayed);\n        PlayerPrefs.Save();\n        Debug.Log(\"Player Profile Saved\");\n    }\n\n    public void SetPlayerName(string name)\n    {\n        playerProfile.playerName = name;\n        SavePlayerProfile();\n    }\n\n    public void SetCountry(string countryCode)\n    {\n        playerProfile.countryCode = countryCode;\n        playerProfile.countryName = GetCountryName(countryCode);\n        SavePlayerProfile();\n    }\n\n    public void AddScore(int score)\n    {\n        playerProfile.totalScore += score;\n        SavePlayerProfile();\n    }\n\n    public void OnLevelCompleted()\n    {\n        playerProfile.totalLevelsCompleted++;\n        playerProfile.currentLevel++;\n        SavePlayerProfile();\n    }\n\n    public void OnEnemyDefeated()\n    {\n        playerProfile.totalEnemiesDefeated++;\n    }\n\n    public void OnGameStarted()\n    {\n        playerProfile.gamesPlayed++;\n        SavePlayerProfile();\n    }\n\n    public PlayerProfile GetPlayerProfile() => playerProfile;\n\n    public string GetCountryName(string countryCode)\n    {\n        // Dictionary of country codes to names\n        var countries = new System.Collections.Generic.Dictionary<string, string>\n        {\n            { \"US\", \"🇺🇸 United States\" },\n            { \"IN\", \"🇮🇳 India\" },\n            { \"GB\", \"🇬🇧 United Kingdom\" },\n            { \"CA\", \"🇨🇦 Canada\" },\n            { \"AU\", \"🇦🇺 Australia\" },\n            { \"FR\", \"🇫🇷 France\" },\n            { \"DE\", \"🇩🇪 Germany\" },\n            { \"JP\", \"🇯🇵 Japan\" },\n            { \"BR\", \"🇧🇷 Brazil\" },\n            { \"MX\", \"🇲🇽 Mexico\" },\n            { \"CN\", \"🇨🇳 China\" },\n            { \"RU\", \"🇷🇺 Russia\" },\n            { \"KR\", \"🇰🇷 South Korea\" },\n            { \"NZ\", \"🇳🇿 New Zealand\" },\n            { \"SG\", \"🇸🇬 Singapore\" },\n            { \"PK\", \"🇵🇰 Pakistan\" },\n            { \"BD\", \"🇧🇩 Bangladesh\" },\n            { \"ZA\", \"🇿🇦 South Africa\" },\n            { \"NG\", \"🇳🇬 Nigeria\" },\n            { \"AR\", \"🇦🇷 Argentina\" },\n        };\n\n        if (countries.TryGetValue(countryCode.ToUpper(), out string name))\n        {\n            return name;\n        }\n        return $\"🌍 {countryCode}\";\n    }\n\n    public string GetCountryFlag(string countryCode)\n    {\n        // Country code to flag emoji\n        var flags = new System.Collections.Generic.Dictionary<string, string>\n        {\n            { \"US\", \"🇺🇸\" }, { \"IN\", \"🇮🇳\" }, { \"GB\", \"🇬🇧\" }, { \"CA\", \"🇨🇦\" },\n            { \"AU\", \"🇦🇺\" }, { \"FR\", \"🇫🇷\" }, { \"DE\", \"🇩🇪\" }, { \"JP\", \"🇯🇵\" },\n            { \"BR\", \"🇧🇷\" }, { \"MX\", \"🇲🇽\" }, { \"CN\", \"🇨🇳\" }, { \"RU\", \"🇷🇺\" },\n            { \"KR\", \"🇰🇷\" }, { \"NZ\", \"🇳🇿\" }, { \"SG\", \"🇸🇬\" }, { \"PK\", \"🇵🇰\" },\n            { \"BD\", \"🇧🇩\" }, { \"ZA\", \"🇿🇦\" }, { \"NG\", \"🇳🇬\" }, { \"AR\", \"🇦🇷\" },\n        };\n\n        if (flags.TryGetValue(countryCode.ToUpper(), out string flag))\n        {\n            return flag;\n        }\n        return \"🌍\";\n    }\n}\n"